import{_ as s,o as a,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"CAN Bus Shield V2.0","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/can-bus/can-bus-shield-v2.0.md","filePath":"obd2/can-bus/can-bus-shield-v2.0.md"}'),n={name:"obd2/can-bus/can-bus-shield-v2.0.md"};function r(l,e,o,p,h,d){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="can-bus-shield-v2-0" tabindex="-1">CAN Bus Shield V2.0 <a class="header-anchor" href="#can-bus-shield-v2-0" aria-label="Permalink to &quot;CAN Bus Shield V2.0&quot;">​</a></h1><h2 id="can-bus-shield-v2-0-1" tabindex="-1">CAN-BUS Shield V2.0 <a href="#can-bus-shield-v20-part-2" id="can-bus-shield-v20-part-2"></a> <a class="header-anchor" href="#can-bus-shield-v2-0-1" aria-label="Permalink to &quot;CAN-BUS Shield V2.0 &lt;a href=&quot;#can-bus-shield-v20-part-2&quot; id=&quot;can-bus-shield-v20-part-2&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><div align="center"><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/shiyitu1.png" alt=""></div><p><strong>CAN-BUS</strong> is a common industrial bus because of its long travel distance, medium communication speed and high reliability. It is commonly found on modern machine tools, such as an automotive diagnostic bus.</p><p>This CAN-BUS Shield adopts <strong>MCP2515</strong> CAN Bus controller with SPI interface and <strong>MCP2551</strong> CAN transceiver to give your Arduino/Seeeduino CAN-BUS capability. With an <strong>OBD-II</strong> converter cable added on and the OBD-II library imported, you are ready to build an onboard diagnostic device or data logger.</p><br><p><a href="https://www.seeedstudio.com/vehicle-hacking-tools" target="_blank" rel="noreferrer"><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/CAN_Car_Hacking.png" alt=""></a></p><p><strong>Version</strong></p><p>This document applies to the following version of products:</p><table tabindex="0"><thead><tr><th><h4>Version</h4></th><th><h4>Released Date</h4></th><th><h4>How to Buy</h4></th></tr></thead><tbody><tr><td><strong>CAN BUS Shield V1.0</strong></td><td><strong>Oct 14, 2012</strong></td><td><img src="https://files.seeedstudio.com/wiki/Seeed-WiKi/docs/images/EOL.png" alt="pir" data-size="original"></td></tr><tr><td><strong>CAN BUS Shield V1.1</strong></td><td><strong>Aug 10, 2013</strong></td><td><img src="https://files.seeedstudio.com/wiki/Seeed-WiKi/docs/images/EOL.png" alt="pir" data-size="original"></td></tr><tr><td><strong>CAN BUS Shield V1.2</strong></td><td><strong>Jan 5, 2015</strong></td><td><img src="https://files.seeedstudio.com/wiki/Seeed-WiKi/docs/images/EOL.png" alt="pir" data-size="original"></td></tr><tr><td><strong>CAN BUS Shield V2.0</strong></td><td><strong>Aug 01,2017</strong></td><td><a href="https://www.seeedstudio.com/CAN-BUS-Shield-V2-p-2921.html" target="_blank" rel="noreferrer"><img src="https://files.seeedstudio.com/wiki/Seeed-WiKi/docs/images/get_one_now_small.png" alt=""></a></td></tr></tbody></table><p><strong>Alternative Choice</strong></p><p>If your project is space limited and also don&#39;t need other fuctions except CAN-BUS, here is a Grove CAN-BUS module which is Arduino compatible, more compact and cost effective, please click <a href="https://www.seeedstudio.com/Serial-CAN-BUS-Module-based-on-MCP2551-and-MCP2515-p-2924.html" target="_blank" rel="noreferrer">here</a> to visit its page.</p><p><a href="https://www.seeedstudio.com/Serial-CAN-BUS-Module-based-on-MCP2551-and-MCP2515-p-2924.html" target="_blank" rel="noreferrer"><img src="https://files.seeedstudio.com/wiki/CAN-BUS-Shield-V2.0/img/canbus_arduino.png" alt=""></a></p><p><strong>What if I want to connect this shield to my car</strong></p><p>If you want to read data or control your car, there&#39;s an OBD&gt;DB9 cable available for you, <a href="https://www.seeedstudio.com/DB9-to-OBD2-Cable-With-Switch-p-2872.html" target="_blank" rel="noreferrer">this cable</a> make easier to connect to OBD-connector and DB9-connector. This cable will also work with anything that has a OBD-connector. Add a power switch makes such a satisfying click.</p><p><a href="https://www.seeedstudio.com/DB9-to-OBD2-Cable-With-Switch-p-2872.html" target="_blank" rel="noreferrer"><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/obd_cable.jpg" alt=""></a></p><p><strong>USB-CAN Analyzer</strong></p><p>If you want a CAN Bus Analyzer to debug your CAN Bus, this <a href="https://www.seeedstudio.com/USB-CAN-Analyzer-p-2888.html" target="_blank" rel="noreferrer">USB-CAN Analyzer</a> is recommended.</p><p><a href="https://www.seeedstudio.com/USB-CAN-Analyzer-p-2888.html" target="_blank" rel="noreferrer"><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/usb_can.jpg" alt=""></a></p><h3 id="features​" tabindex="-1">Features<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#features" target="_blank" rel="noreferrer">​</a> <a href="#features" id="features"></a> <a class="header-anchor" href="#features​" aria-label="Permalink to &quot;Features[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#features) &lt;a href=&quot;#features&quot; id=&quot;features&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li>Implements CAN V2.0B speed up to <strong>1 Mb/s</strong></li><li>SPI Interface speed up to <strong>10 MHz</strong></li><li>Standard (<strong>11 bit</strong>) and extended (<strong>29 bit</strong>) data and remote frames</li><li>Two receive buffers with prioritized message storage</li><li>Industrial standard DB-9 connector</li><li>LED indicators</li></ul><p>NOTE</p><p>CAN BUS Shield Work well with Arduino UNO (ATmega328), Arduino Mega (ATmega1280/2560) as well as Arduino Leonardo (ATmega32U4).</p><h3 id="hardware-overview​" tabindex="-1">Hardware Overview<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#hardware-overview" target="_blank" rel="noreferrer">​</a> <a href="#hardware-overview" id="hardware-overview"></a> <a class="header-anchor" href="#hardware-overview​" aria-label="Permalink to &quot;Hardware Overview[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#hardware-overview) &lt;a href=&quot;#hardware-overview&quot; id=&quot;hardware-overview&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/hardware_overview_1.png" alt="pir"></p><ol><li><strong>DB9 Interface</strong> - to connect to OBDII Interface via a DBG-OBD Cable.</li><li><strong>V_OBD</strong> - It gets power from OBDII Interface (from DB9)</li><li><strong>Led Indicator</strong>: <ul><li><strong>PWR</strong>: power</li><li><strong>TX</strong>: blink when the data is sending</li><li><strong>RX</strong>: blink when there&#39;s data receiving</li><li><strong>INT</strong>: data interrupt</li></ul></li><li><strong>Terminal</strong> - CAN_H and CAN_L</li><li><strong>Arduino UNO pinout</strong></li><li><strong>Serial Grove connector</strong></li><li><strong>I2C Grove connector</strong></li><li><strong>ICSP pins</strong></li><li><strong>IC</strong> - MCP2551, a high-speed CAN transceiver (<a href="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/resource/Mcp2551.pdf" target="_blank" rel="noreferrer">datasheet</a>)</li><li><strong>IC</strong> - MCP2515, stand-alone CAN controller with SPI interface (<a href="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/resource/MCP2515.pdf" target="_blank" rel="noreferrer">datasheet</a>)</li></ol><p>DANGER</p><p>When you use more than two CAN Bus Shields in one net, you should take the impedance into consideration. You should either cut P1 in the PCB with a knife or just remove R3 on the PCB.</p><p><strong>Pin map</strong></p><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/PINMAP.png" alt="pir"></p><p>NOTE</p><p>The FREE pin is available for the other usages.</p><p><strong>DB9&amp;OBDii Interface</strong></p><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/OBD.png" alt="pir"></p><p><strong>CS pin</strong></p><p>CAUTION</p><p>When we produced the new batch of CAN-BUS Shield V2, the wire of the back pads was embedded inside the PCB, although the wire between the pads is now not visible on the outside, the inside is still connected, if you want to change the wiring of the pads, you still need to cut the wiring in the PCB first.</p><p>SPI_CS pin of V1.2 is connected to <strong>D9</strong> by default. If you want to change to <strong>D10</strong>, please follow below instructions.</p><ul><li>Step1: Take a look at the backside of the PCBA, you will find a pad named CS.</li></ul><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/zhanshitu1.png" alt="pir"></p><ul><li>Step2: Cut the wire between pad9 and the middle pad.</li></ul><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/zhanshitu2.png" alt="pir"></p><ul><li>Step3:Solder the middle pad and pad 10.</li></ul><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/zhanshitu3.png" alt="pir"></p><p>DANGER</p><p>Be careful with the box cutter, it&#39;s easy to hurt yourself or the PCBA.</p><p><strong>SPI pins</strong></p><p>The SPI pins (SCK, MISO, MOSI) are routed to the ICSP pins by default. But for some boards, the SPI pins are located at D11~D13. if this happens, you need make some change to the PCBA. Take a look at the backside of the PCBA, there&#39;re three pads, MOSI, MISO and SCK, they are connected to A by default. You can change them to B if needed.</p><p>NOTE</p><p>For Arduino UNO, Arduino Mega, Arduino Leonardo and any others AVR based Arduino boards, it works well by default setting.</p><p>DANGER</p><p>Be careful when you are going to change SPI pins, it&#39;s easy to hurt yourself or the PCBA.</p><h3 id="getting-started​" tabindex="-1">Getting Started<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#getting-started" target="_blank" rel="noreferrer">​</a> <a href="#getting-started" id="getting-started"></a> <a class="header-anchor" href="#getting-started​" aria-label="Permalink to &quot;Getting Started[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#getting-started) &lt;a href=&quot;#getting-started&quot; id=&quot;getting-started&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Here&#39;s a simple example to show you how CAN-BUS Shield works. In this example we need 2 pieces of CAN-BUS Shields as well as Arduino or Seeeduino.</p><p>NOTE</p><p>This example is built under <a href="https://www.arduino.cc/download_handler.php?f=/arduino-1.6.9-windows.zip" target="_blank" rel="noreferrer">Arduino IDE version 1.6.9</a>.</p><p><strong>STEP1: What do we need</strong></p><table tabindex="0"><thead><tr><th><h4>Name</h4></th><th><h4>Function</h4></th><th><h4>Qty</h4></th><th><h4>Link</h4></th></tr></thead><tbody><tr><td><strong>CAN-BUS Shield</strong></td><td><strong>CAN Bus communication</strong></td><td><strong>2</strong></td><td><a href="https://www.seeedstudio.com/CAN-BUS-Shield-V2-p-2921.html" target="_blank" rel="noreferrer">Link</a></td></tr><tr><td><strong>Seeeduino V4.2</strong></td><td><strong>Controller</strong></td><td><strong>2</strong></td><td><a href="https://www.seeedstudio.com/item_detail.html?p_id=2517" target="_blank" rel="noreferrer">Link</a></td></tr></tbody></table><p><strong>STEP2: Hardware Connection</strong></p><p>Insert each CAN-BUS Shield into Seeeduino V4.2, and connect the 2 CAN-BUS Shield together via 2 jumper wires. Shown as below images.</p><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/connection.png" alt="pir"></p><p>NOTE</p><p>CAN_H to CAN_H, CAN_L to CAN_L</p><p><strong>STEP3: Software</strong></p><p>Please follow <a href="https://wiki.seeedstudio.com/How_to_install_Arduino_Library/" target="_blank" rel="noreferrer">how to install an arduino library</a> procedures to install CAN BUS shield library.</p><ul><li>Download the <a href="https://github.com/Seeed-Studio/Seeed_Arduino_CAN" target="_blank" rel="noreferrer"><strong>Seeed_Arduino_CAN</strong></a> Arduino library here.</li></ul><p>Install the library to your Arduino IDE when it is downloaded.</p><p>One of the node (a node means Seeeduino + CAN_BUS Shield) acts as master, the other acts as slaver. The master will send data to slaver constantly.</p><p>NOTE</p><p>Each node can act as master before the code being uploaded.</p><p>Open the <strong>send</strong> example (<strong>File &gt; Examples &gt; Seeed_Arduino_CAN &gt; send</strong>) and upload to the <strong>master</strong>.</p><p><img src="https://files.seeedstudio.com/wiki/CAN-BUS-Shield-V2.0/img/example.png" alt="pir"></p><p>Or copy the following to the Arduino IDE and upload:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## include &lt;SPI.h&gt;</span></span>
<span class="line"><span>## include &quot;mcp2515_can.h&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/*SAMD core*/</span></span>
<span class="line"><span>## ifdef ARDUINO_SAMD_VARIANT_COMPLIANCE</span></span>
<span class="line"><span>    #define SERIAL SerialUSB</span></span>
<span class="line"><span>## else</span></span>
<span class="line"><span>    #define SERIAL Serial</span></span>
<span class="line"><span>## endif</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const int SPI_CS_PIN = 9;</span></span>
<span class="line"><span>mcp2515_can CAN(SPI_CS_PIN); // Set CS pin</span></span>
<span class="line"><span></span></span>
<span class="line"><span>void setup() {</span></span>
<span class="line"><span>    SERIAL.begin(115200);</span></span>
<span class="line"><span>    while(!Serial){};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    while (CAN_OK != CAN.begin(CAN_500KBPS)) {             // init can bus : baudrate = 500k</span></span>
<span class="line"><span>        SERIAL.println(&quot;CAN BUS Shield init fail&quot;);</span></span>
<span class="line"><span>        SERIAL.println(&quot; Init CAN BUS Shield again&quot;);</span></span>
<span class="line"><span>        delay(100);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    SERIAL.println(&quot;CAN BUS Shield init ok!&quot;);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>unsigned char stmp[8] = {0, 0, 0, 0, 0, 0, 0, 0};</span></span>
<span class="line"><span>void loop() {</span></span>
<span class="line"><span>    // send data:  id = 0x00, standrad frame, data len = 8, stmp: data buf</span></span>
<span class="line"><span>    stmp[7] = stmp[7] + 1;</span></span>
<span class="line"><span>    if (stmp[7] == 100) {</span></span>
<span class="line"><span>        stmp[7] = 0;</span></span>
<span class="line"><span>        stmp[6] = stmp[6] + 1;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        if (stmp[6] == 100) {</span></span>
<span class="line"><span>            stmp[6] = 0;</span></span>
<span class="line"><span>            stmp[5] = stmp[6] + 1;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    CAN.sendMsgBuf(0x00, 0, 8, stmp);</span></span>
<span class="line"><span>    delay(100);                       // send data per 100ms</span></span>
<span class="line"><span>    SERIAL.println(&quot;CAN BUS sendMsgBuf ok!&quot;);</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>STEP4: View Result</strong></p><p>Open the Serial Monitor of Arduino IDE(<strong>slaver</strong>), you will get the data sent from the master.</p><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/serial_monitor.png" alt="pir"></p><h3 id="apis​" tabindex="-1">APIs<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#apis" target="_blank" rel="noreferrer">​</a> <a href="#apis" id="apis"></a> <a class="header-anchor" href="#apis​" aria-label="Permalink to &quot;APIs[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#apis) &lt;a href=&quot;#apis&quot; id=&quot;apis&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h4 id="_1-set-the-baud-rate​" tabindex="-1">1.Set the Baud rate<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#1set-the-baud-rate" target="_blank" rel="noreferrer">​</a> <a href="#id-1set-the-baud-rate" id="id-1set-the-baud-rate"></a> <a class="header-anchor" href="#_1-set-the-baud-rate​" aria-label="Permalink to &quot;1.Set the Baud rate[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#1set-the-baud-rate) &lt;a href=&quot;#id-1set-the-baud-rate&quot; id=&quot;id-1set-the-baud-rate&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>This function is used to initialize the baud rate of the CAN Bus system.</p><p>The available baud rates are listed as follows:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## define CAN_5KBPS    1</span></span>
<span class="line"><span>## define CAN_10KBPS   2</span></span>
<span class="line"><span>## define CAN_20KBPS   3</span></span>
<span class="line"><span>## define CAN_25KBPS   4</span></span>
<span class="line"><span>## define CAN_31K25BPS 5</span></span>
<span class="line"><span>## define CAN_33KBPS   6</span></span>
<span class="line"><span>## define CAN_40KBPS   7</span></span>
<span class="line"><span>## define CAN_50KBPS   8</span></span>
<span class="line"><span>## define CAN_80KBPS   9</span></span>
<span class="line"><span>## define CAN_83K3BPS  10</span></span>
<span class="line"><span>## define CAN_95KBPS   11</span></span>
<span class="line"><span>## define CAN_100KBPS  12</span></span>
<span class="line"><span>## define CAN_125KBPS  13</span></span>
<span class="line"><span>## define CAN_200KBPS  14</span></span>
<span class="line"><span>## define CAN_250KBPS  15</span></span>
<span class="line"><span>## define CAN_500KBPS  16</span></span>
<span class="line"><span>## define CAN_666kbps  17</span></span>
<span class="line"><span>## define CAN_1000KBPS 18</span></span></code></pre></div><h3 id="_2-set-receive-mask-and-filter​" tabindex="-1">2.Set Receive Mask and Filter<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#2set-receive-mask-and-filter" target="_blank" rel="noreferrer">​</a> <a href="#id-2set-receive-mask-and-filter" id="id-2set-receive-mask-and-filter"></a> <a class="header-anchor" href="#_2-set-receive-mask-and-filter​" aria-label="Permalink to &quot;2.Set Receive Mask and Filter[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#2set-receive-mask-and-filter) &lt;a href=&quot;#id-2set-receive-mask-and-filter&quot; id=&quot;id-2set-receive-mask-and-filter&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>There are <strong>2</strong> receive mask registers and <strong>5</strong> filter registers on the controller chip that guarantee you getting data from the target device. They are useful especially in a large network consisting of numerous nodes.</p><p>We provide two functions for you to utilize these mask and filter registers. They are:</p><p><strong>Mask:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">init_Mask(unsigned</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> char</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> num,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unsigned</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> char</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ext,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unsigned</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> char</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ulData</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p><strong>Filter:</strong></p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">init_Filt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unsigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> char</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> num</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unsigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> char</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ext</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unsigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> char</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ulData</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><ul><li><strong>num</strong> represents which register to use. You can fill 0 or 1 for mask and 0 to 5 for filter.</li><li><strong>ext</strong> represents the status of the frame. 0 means it&#39;s a mask or filter for a standard frame. 1 means it&#39;s for a extended frame.</li><li><strong>ulData</strong> represents the content of the mask of filter.</li></ul><h4 id="_3-check-receive​" tabindex="-1">3.Check Receive<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#3check-receive" target="_blank" rel="noreferrer">​</a> <a href="#id-3check-receive" id="id-3check-receive"></a> <a class="header-anchor" href="#_3-check-receive​" aria-label="Permalink to &quot;3.Check Receive[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#3check-receive) &lt;a href=&quot;#id-3check-receive&quot; id=&quot;id-3check-receive&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The MCP2515 can operate in either a polled mode, where the software checks for a received frame, or using additional pins to signal that a frame has been received or transmit completed.</p><p>Use the following function to poll for received frames.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">INT8U</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MCP_CAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">checkReceive</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>The function will return 1 if a frame arrives, and 0 if nothing arrives.</p><h4 id="_4-get-can-id​" tabindex="-1">4.Get CAN ID<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#4get-can-id" target="_blank" rel="noreferrer">​</a> <a href="#id-4get-can-id" id="id-4get-can-id"></a> <a class="header-anchor" href="#_4-get-can-id​" aria-label="Permalink to &quot;4.Get CAN ID[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#4get-can-id) &lt;a href=&quot;#id-4get-can-id&quot; id=&quot;id-4get-can-id&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>When some data arrive, you can use the following function to get the CAN ID of the &quot;send&quot; node.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">INT32U</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MCP_CAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getCanId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">void</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h4 id="_5-send-data​" tabindex="-1">5.Send Data<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#5send-data" target="_blank" rel="noreferrer">​</a> <a href="#id-5send-data" id="id-5send-data"></a> <a class="header-anchor" href="#_5-send-data​" aria-label="Permalink to &quot;5.Send Data[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#5send-data) &lt;a href=&quot;#id-5send-data&quot; id=&quot;id-5send-data&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sendMsgBuf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">INT8U</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">INT8U</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ext</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">INT8U</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">data_buf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>It is a function to send data onto the bus. In which:</p><ul><li><strong>id</strong> represents where the data comes from.</li><li><strong>ext</strong> represents the status of the frame. &#39;0&#39; means standard frame. &#39;1&#39; means extended frame.</li><li><strong>len</strong> represents the length of this frame.</li><li><strong>data_buf</strong> is the content of this message.</li></ul><p>For example, In the &#39;send&#39; example, we have:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unsigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> char</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> stmp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sendMsgBuf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x00</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stmp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//send out the message &#39;stmp&#39; to the bus and tell other devices this is a standard frame from 0x00.</span></span></code></pre></div><h4 id="_6-receive-data​" tabindex="-1">6.Receive Data<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#6receive-data" target="_blank" rel="noreferrer">​</a> <a href="#id-6receive-data" id="id-6receive-data"></a> <a class="header-anchor" href="#_6-receive-data​" aria-label="Permalink to &quot;6.Receive Data[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#6receive-data) &lt;a href=&quot;#id-6receive-data&quot; id=&quot;id-6receive-data&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The following function is used to receive data on the &#39;receive&#39; node:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readMsgBuf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unsigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> char</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unsigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> char</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> buf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>In conditions that masks and filters have been set. This function can only get frames that meet the requirements of masks and filters.</p><ul><li><strong>len</strong> represents the data length.</li><li><strong>buf</strong> is where you store the data.</li></ul><h4 id="_7-init-cs​" tabindex="-1">7.init_CS<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#7init_cs" target="_blank" rel="noreferrer">​</a> <a href="#id-7init_cs" id="id-7init_cs"></a> <a class="header-anchor" href="#_7-init-cs​" aria-label="Permalink to &quot;7.init\\_CS[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#7init_cs) &lt;a href=&quot;#id-7init_cs&quot; id=&quot;id-7init_cs&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>it is very usefule for you to use two CAN-BUS shields with one Arduino.we provide CS_CAN pin to select for you.if you cannot kown how to use CS_CAN pin , you can go to <a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#cs_can-pin" target="_blank" rel="noreferrer">CS_CAN pin</a> to learn.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">void</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MCP_CAN::init_CS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">byte</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _CS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><ul><li><strong>_CS</strong> represents what you select pin.(9 or 10)</li></ul><h3 id="generate-a-new-baudrate​" tabindex="-1">Generate a New BaudRate<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#generate-a-new-baudrate" target="_blank" rel="noreferrer">​</a> <a href="#generate-a-new-baudrate" id="generate-a-new-baudrate"></a> <a class="header-anchor" href="#generate-a-new-baudrate​" aria-label="Permalink to &quot;Generate a New BaudRate[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#generate-a-new-baudrate) &lt;a href=&quot;#generate-a-new-baudrate&quot; id=&quot;generate-a-new-baudrate&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>We had provided many frequently-used baud rates, as below:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## define CAN_5KBPS    1</span></span>
<span class="line"><span>## define CAN_10KBPS   2</span></span>
<span class="line"><span>## define CAN_20KBPS   3</span></span>
<span class="line"><span>## define CAN_25KBPS   4</span></span>
<span class="line"><span>## define CAN_31KBPS   5</span></span>
<span class="line"><span>## define CAN_33KBPS   6</span></span>
<span class="line"><span>## define CAN_40KBPS   7</span></span>
<span class="line"><span>## define CAN_50KBPS   8</span></span>
<span class="line"><span>## define CAN_80KBPS   9</span></span>
<span class="line"><span>## define CAN_83KBPS   10</span></span>
<span class="line"><span>## define CAN_95KBPS   11</span></span>
<span class="line"><span>## define CAN_100KBPS  12</span></span>
<span class="line"><span>## define CAN_125KBPS  13</span></span>
<span class="line"><span>## define CAN_200KBPS  14</span></span>
<span class="line"><span>## define CAN_250KBPS  15</span></span>
<span class="line"><span>## define CAN_500KBPS  16</span></span>
<span class="line"><span>## define CAN_666KBPS  17</span></span>
<span class="line"><span>## define CAN_1000KBPS 18</span></span></code></pre></div><p>Yet you may still can&#39;t find the rate you want. Here we provide a software to help you to calculate the baud rate you need.</p><p>Click <a href="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/resource/CAN_Baudrate_CalcV1.3.zip" target="_blank" rel="noreferrer">here</a> to download the software, it&#39;s in Chinese, but never mind, it&#39;s easy to use.</p><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/CAN_BUS_Shield_SetBaud.jpg" alt="pir"></p><p>Open the software, what you need to do is to set the baud rate you want, and then do some simple setting, then click <strong>calculate</strong>.</p><p>Then you will get some data, cfg1, cfg2 and cfg3.</p><p>You need to add some code to the library.</p><p>Open <strong>mcp_can_dfs.h</strong>, you need to add below code at about line 272:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## define MCP_16MHz_xxxkBPS_CFG1 (cfg1)</span><span>    // xxx is the baud rate you need</span></span>
<span class="line"><span>## define MCP_16MHz_xxxkBPS_CFG2 (cfg2)</span></span>
<span class="line"><span>## define MCP_16MHz_xxxkBPS_CFG3 (cfg2)</span></span></code></pre></div><p>Then let&#39;s go to about line 390, add below code:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## define CAN_xxxKBPS NUM</span><span>       // xxx is the baudrate you need, and NUM is a number, you need to get a different from the other rates.</span></span></code></pre></div><p>Open <strong>mcp_can.cpp</strong>, goto the function <strong>mcp2515_configRate</strong>(at about line 190), then add below code:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">case</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CAN_xxxKBPS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">):</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    cfg1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MCP_16MHz_xxxkBPS_CFG1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    cfg2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MCP_16MHz_xxxkBPS_CFG2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    cfg3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MCP_16MHz_xxxkBPS_CFG3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    break</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Then you can use the baud rate you need. And please give me a pull request at github when you use a new rate, so I can add it to the library to help other guys.</p><h3 id="projects​" tabindex="-1">Projects<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#projects" target="_blank" rel="noreferrer">​</a> <a href="#projects" id="projects"></a> <a class="header-anchor" href="#projects​" aria-label="Permalink to &quot;Projects[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#projects) &lt;a href=&quot;#projects&quot; id=&quot;projects&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If you want to make some awesome projects with CAN-BUS shield, here are some projects for reference.</p><h4 id="volkswagen-can-bus-gaming​" tabindex="-1">Volkswagen CAN BUS Gaming<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#volkswagen-can-bus-gaming" target="_blank" rel="noreferrer">​</a> <a href="#volkswagen-can-bus-gaming" id="volkswagen-can-bus-gaming"></a> <a class="header-anchor" href="#volkswagen-can-bus-gaming​" aria-label="Permalink to &quot;Volkswagen CAN BUS Gaming[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#volkswagen-can-bus-gaming) &lt;a href=&quot;#volkswagen-can-bus-gaming&quot; id=&quot;volkswagen-can-bus-gaming&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/project1.JPG" alt="pir"></p><p>Ever wanted to play a car/truck simulator with a real dashboard on your PC? Me too! I&#39;m trying to control a VW Polo 6R dashboard via CAN Bus with an Arduino Uno and a Seeed CAN Bus Shield. Inspired by Silas Parker. Thanks Sepp and Is0-Mick for their great support!</p><p><a href="https://community.seeedstudio.com/project_detail.html?id=291" target="_blank" rel="noreferrer"><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/Wiki_makeitnow_logo.png" alt=""></a></p><h4 id="hack-your-vehicle-can-bus​" tabindex="-1">Hack your vehicle CAN-BUS<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#hack-your-vehicle-can-bus" target="_blank" rel="noreferrer">​</a> <a href="#hack-your-vehicle-can-bus" id="hack-your-vehicle-can-bus"></a> <a class="header-anchor" href="#hack-your-vehicle-can-bus​" aria-label="Permalink to &quot;Hack your vehicle CAN-BUS[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#hack-your-vehicle-can-bus) &lt;a href=&quot;#hack-your-vehicle-can-bus&quot; id=&quot;hack-your-vehicle-can-bus&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/project2.jpg" alt="pir"></p><p>Modern Vehicles all come equipped with a CAN-BUS Controller Area Network, Instead of having a million wires running back and forth from various devices in your car to the battery, its making use of a more clever system.</p><p>All electronic functions are connected to the TIPM, (Totally integrated Power Module), such as solenoids/relays to lock the doors or mini motors to wind the windows etc.</p><p>From each node (IE Switch pod that controls your windows or electric door locks) it broadcasts a message across the CAN. When the TIPM detects a valid message it will react accordingly like, lock the doors, switch on lights and so on.</p><p><a href="https://www.instructables.com/id/Hack-your-vehicle-CAN-BUS-with-Arduino-and-Seeed-C/" target="_blank" rel="noreferrer"><img src="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/image/Wiki_makeitnow_logo.png" alt=""></a></p><h3 id="faq​" tabindex="-1">FAQ<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#faq" target="_blank" rel="noreferrer">​</a> <a href="#faq" id="faq"></a> <a class="header-anchor" href="#faq​" aria-label="Permalink to &quot;FAQ[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#faq) &lt;a href=&quot;#faq&quot; id=&quot;faq&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><hr><p><strong>Q1: I can&#39;t get data from other CAN device.</strong></p><ul><li>Check if the connection is right</li><li>Check if the baud rate setting is right</li></ul><p><strong>Q2: The serial monitor print Init Fail.</strong></p><ul><li>Check if the CS pin setting is matched with the code. For CAN Bus Shield V1.1/1.2, CS pin is connected to D9, others are to D10.</li></ul><h3 id="schematic-online-viewer​" tabindex="-1">Schematic Online Viewer<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#schematic-online-viewer" target="_blank" rel="noreferrer">​</a> <a href="#schematic-online-viewer" id="schematic-online-viewer"></a> <a class="header-anchor" href="#schematic-online-viewer​" aria-label="Permalink to &quot;Schematic Online Viewer[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#schematic-online-viewer) &lt;a href=&quot;#schematic-online-viewer&quot; id=&quot;schematic-online-viewer&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h3 id="resources​" tabindex="-1">Resources<a href="https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#resources" target="_blank" rel="noreferrer">​</a> <a href="#resources" id="resources"></a> <a class="header-anchor" href="#resources​" aria-label="Permalink to &quot;Resources[​](https://wiki.seeedstudio.com/CAN-BUS_Shield_V2.0/#resources) &lt;a href=&quot;#resources&quot; id=&quot;resources&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><hr><ul><li><strong>[PDF]</strong><a href="https://files.seeedstudio.com/wiki/CAN-BUS-Shield-V2.0/res/CAN-BUS%20Shield%20%20v2.0.pdf" target="_blank" rel="noreferrer">CAN-BUS Shield V2.0 Schmatics</a></li><li><strong>[Eagle]</strong><a href="https://files.seeedstudio.com/wiki/CAN-BUS-Shield-V2.0/res/CAN-BUS%20Shield%20%20v2.0.rar" target="_blank" rel="noreferrer">Schematic &amp; PCB of CAN-BUS Shield V2.0</a></li><li><strong>[Library]</strong><a href="https://github.com/Seeed-Studio/CAN_BUS_Shield" target="_blank" rel="noreferrer">Arduino Library for CAN-BUS Shield</a></li><li><strong>[Datasheet]</strong><a href="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/resource/MCP2515.pdf" target="_blank" rel="noreferrer">MCP2515 datasheet</a></li><li><strong>[Datasheet]</strong><a href="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/resource/Mcp2551.pdf" target="_blank" rel="noreferrer">MCP2551 datasheet</a></li><li><strong>[Demo]</strong><a href="https://github.com/Seeed-Studio/CANBUS_SHIELD_OBD_RECIPLE" target="_blank" rel="noreferrer">An OBD Demo</a></li><li><strong>[Tool]</strong><a href="https://files.seeedstudio.com/wiki/CAN_BUS_Shield/resource/CAN_Baudrate_CalcV1.3.zip" target="_blank" rel="noreferrer">MCP2515 Baud Rate Tool</a></li><li><strong>[Tool]</strong><a href="https://www.seeedstudio.com/USB-CAN-Analyzer-p-2888.html" target="_blank" rel="noreferrer">USB-CAN Analyzer</a></li><li><strong>[Cable]</strong><a href="https://www.seeedstudio.com/DB9-to-OBD2-Cable-With-Switch-p-2872.html" target="_blank" rel="noreferrer">DB9 to OBD2 Cable</a></li><li><strong>[Drawing]</strong><a href="https://files.seeedstudio.com/wiki/CAN-BUS-Shield-V2.0/res/CAN-BUS%C2%A0SHIELD%C2%A0V2.0.pdf" target="_blank" rel="noreferrer">CAN BUS Shield v2.0 Drawing in PDF</a></li><li><strong>[Drawing]</strong><a href="https://files.seeedstudio.com/wiki/CAN-BUS-Shield-V2.0/res/CAN-BUS%C2%A0SHIELD%C2%A0V2.0.dxf.zip" target="_blank" rel="noreferrer">CAN BUS Shield v2.0 Drawing in DXF</a></li></ul><br>`,152)])])}const u=s(n,[["render",r]]);export{g as __pageData,u as default};
